using System;
using System.Reflection;
using System.Linq;
using System.Collections.Generic;

namespace ResearchAgent;

public class ApiExplorer
{
    public static void ExploreApis()
    {
        Console.WriteLine("====== MICROSOFT.EXTENSIONS.AI ======\n");
        ExploreAssembly(typeof(Microsoft.Extensions.AI.IChatClient).Assembly, "Microsoft.Extensions.AI");

        Console.WriteLine("\n====== MICROSOFT.AGENTS.AI ======\n");
        ExploreAssembly(typeof(Microsoft.Agents.AI.ChatClientAgent).Assembly, "Microsoft.Agents.AI");
    }

    private static void ExploreAssembly(Assembly assembly, string prefix)
    {
        var publicTypes = assembly.GetTypes()
            .Where(t => t.IsPublic && !t.Name.StartsWith("__") && t.Namespace?.StartsWith(prefix) == true)
            .OrderBy(t => t.Name)
            .ToList();

        // Core Classes
        var coreClasses = publicTypes
            .Where(t => t.IsClass && !t.IsAbstract &&
                (t.Name.Contains("Options") || t.Name.Contains("Agent") || t.Name.Contains("Chat") || 
                 t.Name.Contains("Tool") || t.Name.Contains("Function") || t.Name.Contains("Builder")))
            .ToList();

        Console.WriteLine($"  === CORE CLASSES (non-abstract) ===");
        foreach (var type in coreClasses)
        {
            Console.WriteLine($"\n  class {type.Name}");
            PrintConstructors(type);
            PrintPublicMethods(type, 3);
            PrintPublicProperties(type, 2);
        }

        // Interfaces
        var interfaces = publicTypes
            .Where(t => t.IsInterface)
            .ToList();

        Console.WriteLine($"\n  === INTERFACES ===");
        foreach (var type in interfaces)
        {
            Console.WriteLine($"\n  interface {type.Name}");
            PrintInterfaceMembers(type, 2);
        }

        // Records/ValueTypes
        var records = publicTypes
            .Where(t => (t.IsValueType || t.Name.EndsWith("Options")) && 
                   !t.IsEnum && t.Namespace?.StartsWith(prefix) == true)
            .ToList();

        if (records.Any())
        {
            Console.WriteLine($"\n  === RECORDS/STRUCTS/OPTIONS ===");
            foreach (var type in records)
            {
                Console.WriteLine($"\n  {(type.IsValueType ? "struct" : "class")} {type.Name}");
                PrintConstructors(type);
                PrintPublicProperties(type, 2);
            }
        }
    }

    private static void PrintConstructors(Type type)
    {
        var ctors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
        if (ctors.Length > 0)
        {
            Console.WriteLine("    Constructors:");
            foreach (var ctor in ctors)
            {
                var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                Console.WriteLine($"      .ctor({parms})");
            }
        }
    }

    private static void PrintPublicMethods(Type type, int indent = 3)
    {
        var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
            .Where(m => !m.IsSpecialName && m.DeclaringType == type)
            .ToList();

        if (methods.Any())
        {
            var indentStr = new string(' ', indent * 2);
            Console.WriteLine($"{indentStr}Public Methods:");
            foreach (var method in methods.Take(10))
            {
                var returnType = method.ReturnType.Name;
                var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                var signature = $"{method.Name}({parms})";
                if (method.IsGenericMethod)
                    signature = $"{method.Name}<{string.Join(", ", method.GetGenericArguments().Select(a => a.Name))}>(...)";
                Console.WriteLine($"{indentStr}  {returnType} {signature}");
            }
            if (methods.Count > 10)
                Console.WriteLine($"{indentStr}  ... and {methods.Count - 10} more");
        }
    }

    private static void PrintPublicProperties(Type type, int indent = 2)
    {
        var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
            .Where(p => p.DeclaringType == type)
            .ToList();

        if (props.Any())
        {
            var indentStr = new string(' ', indent * 2);
            Console.WriteLine($"{indentStr}Properties:");
            foreach (var prop in props)
            {
                var getSet = "";
                if (prop.CanRead) getSet += "get; ";
                if (prop.CanWrite) getSet += "set; ";
                Console.WriteLine($"{indentStr}  {prop.PropertyType.Name} {prop.Name} {{ {getSet}}}");
            }
        }
    }

    private static void PrintInterfaceMembers(Type type, int indent = 2)
    {
        var indentStr = new string(' ', indent * 2);
        var methods = type.GetMethods(BindingFlags.Public);
        var properties = type.GetProperties(BindingFlags.Public);

        foreach (var method in methods)
        {
            var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"{indentStr}{method.ReturnType.Name} {method.Name}({parms});");
        }

        foreach (var prop in properties)
        {
            var getSet = "";
            if (prop.CanRead) getSet += "get; ";
            if (prop.CanWrite) getSet += "set; ";
            Console.WriteLine($"{indentStr}{prop.PropertyType.Name} {prop.Name} {{ {getSet}}}");
        }
    }
}
