## TYPICAL USAGE FLOW

```csharp
// 1. Create IChatClient (from OpenAI or other provider)
IChatClient chatClient = new OpenAIChatClient(...);

// 2. Create ChatClientAgentOptions
var agentOptions = new ChatClientAgentOptions
{
    Id = "my-agent",
    Name = "Research Agent",
    Description = "Analyzes research questions",
    ChatOptions = new ChatOptions
    {
        ModelId = "gpt-4",
        Temperature = 0.7f,
        MaxOutputTokens = 2000
    }
};

// 3. Create agent
var agent = new ChatClientAgent(
    chatClient,
    agentOptions,
    loggerFactory,
    services
);

// 4. Create session
var session = await agent.CreateSessionAsync(null, cancellationToken);

// 5. Run agent
var runOptions = new ChatClientAgentRunOptions(
    new ChatOptions { Tools = myTools }
);

var response = await agent.RunAsync(
    "What is the capital of France?",
    session,
    runOptions,
    cancellationToken
);

// 6. Get response
Console.WriteLine(response.Text);
foreach (var msg in response.Messages)
{
    // Handle tool calls, context, etc.
}
```

