9. COMPLETE BASIC WIRING EXAMPLE
─────────────────────────────────

// 1. Setup
var loggerFactory = LoggerFactory.Create(b => b.AddConsole());
var services = new ServiceCollection().BuildServiceProvider();

// 2. Create chat client from provider (e.g., OpenAI)
IChatClient chatClient = new OpenAIChatClient("gpt-4", "your-api-key");

// 3. Create agent options
var agentOptions = new ChatClientAgentOptions
{
    Id = "research-agent",
    Name = "Research Assistant",
    Description = "Helps with research tasks",
    ChatOptions = new ChatOptions
    {
        ModelId = "gpt-4",
        Temperature = 0.7f,
        MaxOutputTokens = 2000,
        Tools = new List<AITool>() // Add tools here
    }
};

// 4. Create agent
var agent = new ChatClientAgent(chatClient, agentOptions, loggerFactory, services);

// 5. Create session
var session = await agent.CreateSessionAsync("conv-123", cancellationToken);

// 6. Run agent
var runOptions = new ChatClientAgentRunOptions(agentOptions.ChatOptions);

var response = await agent.RunAsync(
    "What are the key findings in quantum computing?",
    session,
    runOptions,
    cancellationToken
);

// 7. Process response
Console.WriteLine($"Response: {response.Text}");

foreach (var msg in response.Messages)
{
    Console.WriteLine($"[{msg.Role}]: {msg.Text}");

    // Handle tool calls
    foreach (var content in msg.Contents)
    {
        if (content is FunctionCallContent toolCall)
        {
            Console.WriteLine($"Tool call: {toolCall.Name}");
            Console.WriteLine($"Args: {string.Join(", ", toolCall.Arguments)}");
        }
    }
}


10. SECURITY CONSIDERATIONS
────────────────────────────

⚠️ Important Warnings from ChatClientAgent XML Docs:

  • Hallucination: LLMs generate plausible but incorrect information.
    → Verify LLM output independently.

  • Indirect Prompt Injection: Retrieved data and history may contain
    adversarial content designed to influence LLM behavior.
    → Validate all data sources and retrieved context.

  • Malicious Payloads: LLM output may contain harmful content
    (HTML/XSS, SQL injection, shell commands).
    → Sanitize output before rendering or execution.

  • Tool Invocation: By default, ALL tools are invoked without approval.
    → Apply tool approval patterns for sensitive operations.
    → Treat function arguments as untrusted input.


